export type EmailTemplateKey = 'blank' | 'diagnostic' | 'refonte' | 'migration' | 'support' | 'support-simple' | 'support-ticket' | 'support-en' | 'creation' | 'optimisation';

export type EmailTemplateSetting = {
  key: EmailTemplateKey;
  subject: string;
  body: string;
};

export type EmailTemplateDefinition = EmailTemplateSetting & {
  label: string;
};

export type SiteLinkSetting = {
  supportUrl: string;
  creationUrl: string;
  refonteUrl: string;
  migrationUrl: string;
  optimizationUrl: string;
  diagnosticUrl: string;
};

export type EmailSendingSetting = {
  paused: boolean;
  sendAtHour: number;
  sendUntilHour: number;
  dailyLimit: number;
};

export type DiscordReminderSetting = {
  sendAtTime: string;
};

export type EmailSignatureSetting = {
  html: string;
};

export type HomepageCardSetting = {
  key: string;
  position: number;
  visible: boolean;
};

export type HomepageCardsResponse = {
  blocks: HomepageCardSetting[];
};

export type EmailTemplatesResponse = {
  templates: EmailTemplateDefinition[];
};

export type SiteLinksResponse = SiteLinkSetting;

export type EmailSendingResponse = EmailSendingSetting;

export type DiscordReminderResponse = DiscordReminderSetting;

export type EmailSignatureResponse = EmailSignatureSetting;

export type LeadScoreSettingsResponse = LeadScoreSettings;

export type ScanStepsResponse = ScanStepsSettings;

export type ScanTimeoutSetting = {
  timeoutMs: number;
};

export type ScanTimeoutResponse = ScanTimeoutSetting;

export type ProspectRelaunchSetting = {
  afterDays: number;
};

export type ProspectRelaunchResponse = ProspectRelaunchSetting;

